# Error Handling Refactor — Phase 3 Design

## Preliminary Review of Prior Decisions

Before writing a single line of design, I'm reviewing all binding decisions from Phases 1 and 2:

| Source | Binding Requirement |
|---|---|
| ADR-001 | JWT tokens must use RS256. Auth middleware validates signature, expiry, audience, issuer. |
| ADR-002 | Rate limit 429 responses MUST include `Retry-After`. All responses include `X-RateLimit-*` headers. |
| ADR-003 | ALL error responses use RFC 9457 (`application/problem+json`). No custom formats. |
| SEC-2025-041 (CRITICAL) | RS256 only. HS256 tokens must be rejected. |
| Partner SLA (HIGH) | `Retry-After` on 429 is a contractual obligation. |
| Error Handling doc | Distinguish 401 vs 403. Include `trace_id`. Suppress stack traces in production. |
| PCI-DSS Req 10 | No cardholder data (even last-4) in logs. Full error details logged internally, not exposed. |

---

## 1. Global Error Handling Strategy

### 1.1 Error Type Hierarchy

All application errors extend a single base class. This ensures every thrown error carries the information needed to produce a valid RFC 9457 response, and nothing else reaches the global handler as an untyped `Error`.

```typescript
// src/errors/base.ts

export interface ProblemDetails {
  type: string;
  title: string;
  status: number;
  detail: string;
  instance: string;
  trace_id?: string;
  [extension: string]: unknown; // RFC 9457 allows extension fields
}

export abstract class ApiError extends Error {
  abstract readonly type: string;
  abstract readonly title: string;
  abstract readonly status: number;

  constructor(
    public readonly detail: string,
    public readonly extensions: Record<string, unknown> = {}
  ) {
    super(detail);
    // Maintains proper prototype chain in transpiled TypeScript
    Object.setPrototypeOf(this, new.target.prototype);
  }

  toProblemDetails(instance: string, traceId: string): ProblemDetails {
    return {
      type: `https://api.payments.example/errors/${this.type}`,
      title: this.title,
      status: this.status,
      detail: this.detail,
      instance,
      trace_id: traceId,
      ...this.extensions,
    };
  }
}
```

### 1.2 Complete Error Type Registry

Every error type registered in ADR-003 plus the missing types identified in the Error Handling doc:

```typescript
// src/errors/types.ts

import { ApiError } from './base';

// ── 400 Validation ────────────────────────────────────────────────────────────

export interface ValidationFailure {
  field: string;
  message: string;
}

export class ValidationError extends ApiError {
  readonly type = 'validation-failed';
  readonly title = 'Validation Failed';
  readonly status = 400;

  constructor(failures: ValidationFailure[]) {
    super(`${failures.length} validation error(s) in request body`, {
      validation_errors: failures,
    });
  }
}

export class InvalidPaymentMethodError extends ApiError {
  readonly type = 'invalid-payment-method';
  readonly title = 'Invalid Payment Method';
  readonly status = 400;
}

// ── 401 Authentication ────────────────────────────────────────────────────────
//
// DESIGN NOTE: 401 and 403 are deliberately separate error types with separate
// type URIs. This distinction is required by the Error Handling doc and is
// important for clients: 401 means "authenticate or re-authenticate",
// 403 means "you are authenticated but not allowed — do not retry with
// the same credentials."

export class AuthenticationRequiredError extends ApiError {
  readonly type = 'authentication-required';
  readonly title = 'Authentication Required';
  readonly status = 401;
  // WWW-Authenticate header is set separately in the global handler
}

export class InvalidTokenError extends ApiError {
  readonly type = 'authentication-required';
  readonly title = 'Authentication Required';
  readonly status = 401;
  // Same type URI as AuthenticationRequiredError — both mean "get a valid token"
}

export class ExpiredTokenError extends ApiError {
  readonly type = 'authentication-required';
  readonly title = 'Authentication Required';
  readonly status = 401;
  // detail will say "token has expired" — client knows to refresh
}

// ── 403 Authorization ─────────────────────────────────────────────────────────

export class PermissionDeniedError extends ApiError {
  readonly type = 'permission-denied';
  readonly title = 'Permission Denied';
  readonly status = 403;
}

// ── 402 Payment ───────────────────────────────────────────────────────────────

export class InsufficientFundsError extends ApiError {
  readonly type = 'insufficient-funds';
  readonly title = 'Insufficient Funds';
  readonly status = 402;
}

export class CardDeclinedError extends ApiError {
  readonly type = 'card-declined';
  readonly title = 'Card Declined';
  readonly status = 402;
}

// ── 404 Not Found ─────────────────────────────────────────────────────────────

export class PaymentNotFoundError extends ApiError {
  readonly type = 'payment-not-found';
  readonly title = 'Payment Not Found';
  readonly status = 404;
}

export class SubscriptionNotFoundError extends ApiError {
  // Previously missing from registry — added per Error Handling doc
  readonly type = 'subscription-not-found';
  readonly title = 'Subscription Not Found';
  readonly status = 404;
}

// ── 409 Conflict ──────────────────────────────────────────────────────────────

export class IdempotencyConflictError extends ApiError {
  readonly type = 'idempotency-conflict';
  readonly title = 'Idempotency Conflict';
  readonly status = 409;
}

export class RefundExceedsAmountError extends ApiError {
  // Previously missing from registry — added per Error Handling doc
  readonly type = 'refund-exceeds-amount';
  readonly title = 'Refund Exceeds Original Amount';
  readonly status = 409;
}

// ── 422 Webhook ───────────────────────────────────────────────────────────────

export class WebhookVerificationFailedError extends ApiError {
  // Previously missing from registry — added per Error Handling doc
  readonly type = 'webhook-verification-failed';
  readonly title = 'Webhook Verification Failed';
  readonly status = 422;
}

// ── 429 Rate Limiting ─────────────────────────────────────────────────────────

export class RateLimitedError extends ApiError {
  readonly type = 'rate-limited';
  readonly title = 'Too Many Requests';
  readonly status = 429;

  constructor(
    detail: string,
    public readonly retryAfterSeconds: number
  ) {
    super(detail, {
      // RFC 9457 extension field mirrors the Retry-After header value.
      // The global handler also sets the header — both must be present.
      retry_after: retryAfterSeconds,
    });
  }
}

// ── 502 Gateway ───────────────────────────────────────────────────────────────

export class GatewayError extends ApiError {
  readonly type = 'gateway-error';
  readonly title = 'Payment Gateway Error';
  readonly status = 502;
}
```

### 1.3 Global Error Handler

This is the single Express error-handling middleware registered last in the middleware chain. It is the only place that writes error responses — no route handler writes its own error response format.

```typescript
// src/middleware/errorHandler.ts

import { Request, Response, NextFunction } from 'express';
import { ApiError, ProblemDetails } from '../errors/base';
import { RateLimitedError } from '../errors/types';
import { logger } from '../lib/logger';

const ERROR_REGISTRY_BASE = 'https://api.payments.example/errors';

export function globalErrorHandler(
  err: unknown,
  req: Request,
  res: Response,
  // next is required by Express for error handlers even if unused
  _next: NextFunction
): void {
  const traceId: string = (req as any).traceId ?? 'unknown';
  const instance = req.path;

  // ── Case 1: Known ApiError ─────────────────────────────────────────────────
  if (err instanceof ApiError) {
    const body = err.toProblemDetails(instance, traceId);

    // Log at appropriate level. 5xx = error, 4xx = warn (expected client errors)
    const logLevel = body.status >= 500 ? 'error' : 'warn';
    logger[logLevel]('API error', {
      trace_id: traceId,
      status: body.status,
      type: body.type,
      detail: body.detail,
      // IMPORTANT: Do NOT log full request body here — may contain card data.
      // PCI-DSS Req 10: cardholder data must not appear in logs.
      path: req.path,
      method: req.method,
    });

    // Special headers for specific error types
    if (body.status === 401) {
      res.setHeader(
        'WWW-Authenticate',
        'Bearer realm="payments-api", error="invalid_token"'
      );
    }

    if (err instanceof RateLimitedError) {
      // CRITICAL: Retry-After is a contractual obligation per partner SLA.
      // It must appear as BOTH a response header AND in the body (retry_after
      // extension field). The header is the HTTP standard; the body field is
      // for clients that parse the problem details object.
      res.setHeader('Retry-After', String(err.retryAfterSeconds));
      // X-RateLimit-* headers are set by the rate limiting middleware upstream;
      // they should already be on the response. We assert here in development.
      if (process.env.NODE_ENV === 'development') {
        assertRateLimitHeaders(res, traceId);
      }
    }

    res
      .status(body.status)
      .contentType('application/problem+json')
      .json(body);
    return;
  }

  // ── Case 2: Unhandled / unexpected error ───────────────────────────────────
  //
  // This should not happen in normal operation. If it does, it means a code
  // path threw a raw Error instead of an ApiError. We log the full error
  // (including stack) internally but return a generic 500 to the client.
  // Stack traces MUST NOT be sent to clients (security + PCI-DSS).

  logger.error('Unhandled error — this is a bug', {
    trace_id: traceId,
    path: req.path,
    method: req.method,
    error: err instanceof Error ? err.message : String(err),
    // Stack is logged internally only, never sent to client
    stack: err instanceof Error ? err.stack : undefined,
  });

  const fallback: ProblemDetails = {
    type: `${ERROR_REGISTRY_BASE}/internal-error`,
    title: 'Internal Server Error',
    status: 500,
    detail: 'An unexpected error occurred. Please try again or contact support.',
    instance,
    trace_id: traceId,
  };

  res
    .status(500)
    .contentType('application/problem+json')
    .json(fallback);
}

function assertRateLimitHeaders(res: Response, traceId: string): void {
  const required = ['X-RateLimit-Limit', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'];
  for (const header of required) {
    if (!res.getHeader(header)) {
      logger.warn(`Rate limit response missing ${header}`, { trace_id: traceId });
    }
  }
}
```

